@dataclass
class PackageHash:
    """Represents a cryptographic hash for a package distribution file."""
    algorithm: str
    digest: str

    def __str__(self):
        return f"{self.algorithm}:{self.digest}"

    @classmethod
    def from_string(cls, hash_string: str) -> "PackageHash":
        algorithm, digest = hash_string.split(":", 1)
        return cls(algorithm=algorithm, digest=digest)


@dataclass
class LockedDependency:
    """Represents a single locked dependency with version and integrity hashes."""
    name: str
    version: str
    hashes: list = field(default_factory=list)
    index_url: str = "https://pypi.org/simple"
    is_direct: bool = False
    markers: str = ""
    extras: list = field(default_factory=list)

    def to_requirements_line(self) -> str:
        """Format as a pip requirements.txt line with hashes."""
        line = f"{self.name}=={self.version}"
        if self.markers:
            line += f" ; {self.markers}"
        if self.hashes:
            hash_parts = " \\\n    ".join(
                f"--hash={h}" for h in self.hashes
            )
            line += f" \\\n    {hash_parts}"
        return line

    def to_dict(self) -> dict:
        return {
            "name": self.name,
            "version": self.version,
            "hashes": [str(h) for h in self.hashes],
            "index_url": self.index_url,
            "is_direct": self.is_direct,
            "markers": self.markers,
            "extras": self.extras,
        }

    @classmethod
    def from_dict(cls, data: dict) -> "LockedDependency":
        return cls(
            name=data["name"],
            version=data["version"],
            hashes=[PackageHash.from_string(h) for h in data.get("hashes", [])],
            index_url=data.get("index_url", "https://pypi.org/simple"),
            is_direct=data.get("is_direct", False),
            markers=data.get("markers", ""),
            extras=data.get("extras", []),
        )


@dataclass
class LockFile:
    """Represents a complete dependency lock file."""
    dependencies: dict = field(default_factory=dict)  # name -> LockedDependency
    metadata: dict = field(default_factory=dict)
    created_at: str = ""
    python_version: str = ""
    platform: str = ""

    def __post_init__(self):
        if not self.created_at:
            self.created_at = datetime.now(timezone.utc).isoformat()
        if not self.python_version:
            self.python_version = f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}"
        if not self.platform:
            self.platform = sys.platform


# =============================================================================
# Hash Computation and Verification
# =============================================================================

class IntegrityVerifier:
    """Handles cryptographic hash computation and verification for packages."""

    SUPPORTED_ALGORITHMS = ("sha256", "sha384", "sha512")
    DEFAULT_ALGORITHM = "sha256"

    @staticmethod
    def compute_file_hash(filepath: str, algorithm: str = "sha256") -> PackageHash:
        """Compute the cryptographic hash of a file."""
        if algorithm not in IntegrityVerifier.SUPPORTED_ALGORITHMS:
            raise ValueError(
                f"Unsupported algorithm: {algorithm}. "
                f"Supported: {IntegrityVerifier.SUPPORTED_ALGORITHMS}"
            )

        hasher = hashlib.new(algorithm)
        with open(filepath, "rb") as f:
            while True:
                chunk = f.read(8192)
                if not chunk:
                    break
                hasher.update(chunk)

        return PackageHash(algorithm=algorithm, digest=hasher.hexdigest())

    @staticmethod
    def verify_file_hash(filepath: str, expected_hash: PackageHash) -> bool:
        """Verify a file against an expected hash."""
        actual_hash = IntegrityVerifier.compute_file_hash(
            filepath, expected_hash.algorithm
        )
        return actual_hash.digest == expected_hash.digest

    @staticmethod
    def fetch_pypi_hashes(
        package_name: str, version: str, algorithm: str = "sha256"
    ) -> list:
        """Fetch package hashes from PyPI JSON API."""
        url = f"https://pypi.org/pypi/{package_name}/{version}/json"
        try:
            with urlopen(url, timeout=30) as response:
                data = json.loads(response.read().decode())

            hashes = []
            for file_info in data.get("urls", []):
                digests = file_info.get("digests", {})
                if algorithm in digests:
                    hashes.append(
                        PackageHash(algorithm=algorithm, digest=digests[algorithm])
                    )
            return hashes
        except (URLError, json.JSONDecodeError, KeyError) as e:
            logger.warning(f"Failed to fetch hashes for {package_name}=={version}: {e}")
            return []


