class LockFileManager:
    """Manages reading, writing, and manipulating lock files."""

    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_in = self.project_root / "requirements.in"
        self.requirements_dev_in = self.project_root / "requirements-dev.in"
        self.requirements_lock = self.project_root / "requirements.lock"
        self.requirements_dev_lock = self.project_root / "requirements-dev.lock"
        self.lock_json = self.project_root / "dependency-lock.json"
        self.verifier = IntegrityVerifier()

    # -------------------------------------------------------------------------
    # Requirements.in Parsing
    # -------------------------------------------------------------------------

    def parse_requirements_in(self, filepath: Optional[Path] = None) -> list:
        """
        Parse a requirements.in file (human-maintained input file).

        The requirements.in file should contain direct dependencies with
        flexible version constraints:

            # requirements.in
            flask>=2.0,<3.0
            sqlalchemy~=2.0
            redis>=4.0
            gunicorn>=21.0

        Returns a list of requirement strings.
        """
        filepath = filepath or self.requirements_in
        if not filepath.exists():
            logger.error(f"Requirements input file not found: {filepath}")
            return []

        requirements = []
        with open(filepath, "r") as f:
            for line in f:
                line = line.strip()
                # Skip empty lines and comments
                if not line or line.startswith("#"):
                    continue
                # Skip options like --index-url
                if line.startswith("-"):
                    continue
                requirements.append(line)

        logger.info(f"Parsed {len(requirements)} requirements from {filepath}")
        return requirements

    # -------------------------------------------------------------------------
    # Lock File Generation
    # -------------------------------------------------------------------------

    def generate_lock_file(
        self,
        input_file: Optional[Path] = None,
        output_file: Optional[Path] = None,
        include_hashes: bool = True,
        python_version: Optional[str] = None,
    ) -> LockFile:
        """
        Generate a lock file from a requirements.in file.

        This resolves all dependencies (including transitive ones),
        pins exact versions, and fetches cryptographic hashes.

        Steps:
            1. Read requirements.in for direct dependency specifications
            2. Use pip-compile (or pip resolver) to resolve all versions
            3. Fetch SHA256 hashes from PyPI for each resolved package
            4. Write the lock file with pinned versions and hashes
        """
        input_file = input_file or self.requirements_in
        output_file = output_file or self.requirements_lock

        if not input_file.exists():
            logger.error(f"Input file not found: {input_file}")
            raise FileNotFoundError(f"Input file not found: {input_file}")

        logger.info(f"Generating lock file from {input_file}")

        # Step 1: Resolve dependencies using pip-compile or fallback
        resolved = self._resolve_dependencies(input_file, python_version)

        # Step 2: Fetch hashes for each resolved package
        lock = LockFile()
        direct_deps = {
            self._normalize_name(r.split("[")[0].split(">")[0].split("<")[0].split("=")[0].split("~")[0].split("!")[0].strip())
            for r in self.parse_requirements_in(input_file)
        }

        for name, version in resolved.items():
            normalized_name = self._normalize_name(name)
            hashes = []
            if include_hashes:
                logger.info(f"Fetching hashes for {normalized_name}=={version}")
                hashes = self.verifier.fetch_pypi_hashes(normalized_name, version)

            dep = LockedDependency(
                name=normalized_name,
                version=version,
                hashes=hashes,
                is_direct=normalized_name in direct_deps,
            )
            lock.dependencies[normalized_name] = dep

        # Step 3: Write lock files
        self._write_requirements_lock(lock, output_file)
        self._write_json_lock(lock)

        logger.info(
            f"Lock file generated with {len(lock.dependencies)} packages "
            f"({sum(1 for d in lock.dependencies.values() if d.is_direct)} direct, "
            f"{sum(1 for d in lock.dependencies.values() if not d.is_direct)} transitive)"
        )

        return lock

    def _resolve_dependencies(
        self, input_file: Path, python_version: Optional[str] = None
    ) -> dict:
        """
        Resolve all dependencies to exact versions.

        Tries pip-compile first (from pip-tools), falls back to pip freeze approach.
        """
        # Try pip-compile first (preferred)
        resolved = self._try_pip_compile(input_file, python_version)
        if resolved:
            return resolved

        # Fallback: install into a temporary venv and freeze
        logger.info("pip-compile not available, falling back to pip freeze approach")
        return self._resolve_via_pip_install(input_file)

    def _try_pip_compile(
        self, input_file: Path, python_version: Optional[str] = None
    ) -> Optional[dict]:
        """Attempt to resolve dependencies using pip-compile from pip-tools."""
        try:
            with tempfile.NamedTemporaryFile(
                mode="w", suffix=".txt", delete=False
            ) as tmp:
                tmp_path = tmp.name

            cmd = [
                sys.executable, "-m", "piptools", "compile",
                "--generate-hashes",
                "--output-file", tmp_path,
                "--no-header",
                "--no-annotate",
                str(input_file),
            ]

            if python_version:
                cmd.extend(["--python-version", python_version])

            result = subprocess.run(
                cmd, capture_output=True, text=True, timeout=300
            )

            if result.returncode != 0:
                logger.debug(f"pip-compile failed: {result.stderr}")
                return None

            return self._parse_compiled_requirements(tmp_path)

        except (subprocess.TimeoutExpired, FileNotFoundError) as e:
            logger.debug(f"pip-compile not available: {e}")
            return None
        finally:
            if os.path.exists(tmp_path):
                os.unlink(tmp_path)

    def _resolve_via_pip_install(self, input_file: Path) -> dict:
        """Resolve dependencies by doing a dry-run pip install."""
        try:
            cmd = [
                sys.executable, "-m", "pip", "install",
                "--dry-run",
                "--report", "-",
                "-r", str(input_file),
            ]

            result = subprocess.run(
                cmd, capture_output=True, text=True, timeout=300
            )

            if result.returncode == 0 and result.stdout:
                try:
                    report = json.loads(result.stdout)
                    resolved = {}
                    for item in report.get("install", []):
                        metadata = item.get("metadata", {})
                        name = metadata.get("name", "")
                        version = metadata.get("version", "")
                        if name and version:
                            resolved[self._normalize_name(name)] = version
                    if resolved:
                        return resolved
                except json.JSONDecodeError:
                    pass

            # Final fallback: parse pip freeze output from current environment
            logger.warning(
                "Using current environment packages as fallback. "
                "Consider installing pip-tools for proper resolution."
            )
            return self._get_installed_packages()

        except subprocess.TimeoutExpired:
            logger.error("Dependency resolution timed out")
            return self._get_installed_packages()

    def _get_installed_packages(self) -> dict:
        """Get currently installed packages as a fallback."""
        result = subprocess.run(
            [sys.executable, "-m", "pip", "freeze"],
            capture_output=True, text=True,
        )
        resolved = {}
        for line in result.stdout.strip().split("\n"):
            line = line.strip()
            if "==" in line and not line.startswith("#"):
                name, version = line.split("==", 1)
                resolved[self._normalize_name(name)] = version
        return resolved

    def _parse_compiled_requirements(self, filepath: str) -> dict:
        """Parse pip-compile output to extract package versions."""
        resolved = {}
        with open(filepath, "r") as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith("#") or line.startswith("--"):
                    continue
                # Remove hash suffixes and backslash continuations
                line = line.rstrip("\\").strip()
                match = re.match(r"^([a-zA-Z0-9_.-]+)==([^\s;\\]+)", line)
                if match:
                    name = self._normalize_name(match.group(1))
                    version = match.group(2)
                    resolved[name] = version
        return resolved

    # -------------------------------------------------------------------------
    # Lock File Writing
    # -------------------------------------------------------------------------

    def _write_requirements_lock(self, lock: LockFile, output_file: Path):
        """Write lock file in pip requirements.txt format with hashes."""
        with open(output_file, "w") as f:
            f.write(
                f"#\n"
                f"# This file is auto-generated by dependency_manager.py\n"
                f"# DO NOT EDIT MANUALLY\n"
                f"#\n"
                f"# Generated: {lock.created_at}\n"
                f"# Python: {lock.python_version}\n"
                f"# Platform: {lock.platform}\n"
                f"#\n"
                f"# To regenerate: python dependency_manager.py generate\n"
                f"# To install:    pip install --require-hashes -r {output_file.name}\n"
                f"#\n\n"
            )

            # Write direct dependencies first
            direct = sorted(
                [d for d in lock.dependencies.values() if d.is_direct],
                key=lambda d: d.name,
            )
            transitive = sorted(
                [d for d in lock.dependencies.values() if not d.is_direct],
                key=lambda d: d.name,
            )

            if direct:
                f.write("# Direct dependencies\n")
                for dep in direct:
                    f.write(dep.to_requirements_line() + "\n")
                f.write("\n")

            if transitive:
                f.write("# Transitive (indirect) dependencies\n")
                for dep in transitive:
                    f.write(dep.to_requirements_line() + "\n")

        logger.info(f"Written requirements lock file: {output_file}")

    def _write_json_lock(self, lock: LockFile):
        """Write lock file in JSON format for programmatic access."""
        data = {
            "metadata": {
                "generated_at": lock.created_at,
                "python_version": lock.python_version,
                "platform": lock.platform,
                "generator": "dependency_manager.py",
                "version": "1.0.0",
            },
            "dependencies": {
                name: dep.to_dict()
                for name, dep in sorted(lock.dependencies.items())
            },
        }

        with open(self.lock_json, "w") as f:
            json.dump(data, f, indent=2, sort_keys=True)
            f.write("\n")

        logger.info(f"Written JSON lock file: {self.lock_json}")

    # -------------------------------------------------------------------------
    # Lock File Reading
    # -------------------------------------------------------------------------

    def read_lock_file(self, filepath: Optional[Path] = None) -> LockFile:
        """Read and parse an existing lock file."""
        # Try JSON format first
        if self.lock_json.exists():
            return self._read_json_lock()

        # Fall back to requirements.lock format
        filepath = filepath or self.requirements_lock
        if filepath.exists():
            return self._read_requirements_lock(filepath)

        raise FileNotFoundError("No lock file found")

    def _read_json_lock(self) -> LockFile:
        """Read lock file from JSON format."""
        with open(self.lock_json, "r") as f:
            data = json.load(f)

        lock = LockFile(
            created_at=data["metadata"]["generated_at"],
            python_version=data["metadata"]["python_version"],
            platform=data["metadata"]["platform"],
        )

        for name, dep_data in data.get("dependencies", {}).items():
            lock.dependencies[name] = LockedDependency.from_dict(dep_data)

        return lock

    def _read_requirements_lock(self, filepath: Path) -> LockFile:
        """Read lock file from requirements.txt format."""
        lock = LockFile()

        with open(filepath, "r") as f:
            content = f.read()

        # Join continuation lines
        content = content.replace("\\\n", " ")

        for line in content.split("\n"):
            line = line.strip()
            if not line or line.startswith("#") or line.startswith("-"):
                continue

            # Parse package==version with optional hashes
            match = re.match(r"^([a-zA-Z0-9_.-]+)==([^\s;]+)", line)
            if match:
                name = self._normalize_name(match.group(1))
                version = match.group(2)

                hashes = []
                for hash_match in re.finditer(r"--hash=(\S+)", line):
                    hashes.append(PackageHash.from_string(hash_match.group(1)))

                lock.dependencies[name] = LockedDependency(
                    name=name,
                    version=version,
                    hashes=hashes,
                )

        return lock

    # -------------------------------------------------------------------------
    # Verification
    # -------------------------------------------------------------------------

    def verify_environment(self) -> dict:
        """
        Verify that installed packages match the lock file.

        Returns a report dict with:
            - matched: packages that match the lock file
            - mismatched: packages with wrong versions
            - missing: packages in lock file but not installed
            - extra: packages installed but not in lock file
            - hash_failures: packages whose hashes don't match
        """
        logger.info("Verifying environment against lock file...")

        try:
            lock = self.read_lock_file()
        except FileNotFoundError:
            logger.error("No lock file found. Run 'generate' first.")
            return {"error": "No lock file found"}

        installed = self._get_installed_packages()

        report = {
            "matched": [],
            "mismatched": [],
            "missing": [],
            "extra": [],
            "hash_failures": [],
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }

        locked_names = set(lock.dependencies.keys())
        installed_names = set(installed.keys())

        # Check for missing packages
        for name in locked_names - installed_names:
            report["missing"].append({
                "name": name,
                "expected_version": lock.dependencies[name].version,
            })

        # Check for extra packages (not in lock file)
        # Exclude pip, setuptools, wheel as they're typically pre-installed
        system_packages = {"pip", "setuptools", "wheel", "pkg-resources"}
        for name in installed_names - locked_names - system_packages:
            report["extra"].append({
                "name": name,
                "installed_version": installed[name],
            })

        # Check version matches
        for name in locked_names & installed_names:
            expected = lock.dependencies[name].version
            actual = installed[name]
            if expected == actual:
                report["matched"].append({
                    "name": name,
                    "version": actual,
                })
            else:
                report["mismatched"].append({
                    "name": name,
                    "expected_version": expected,
                    "installed_version": actual,
                })

        # Summary
        total = len(locked_names)
        matched = len(report["matched"])
        logger.info(
            f"Verification complete: {matched}/{total} packages match, "
            f"{len(report['mismatched'])} mismatched, "
            f"{len(report['missing'])} missing, "
            f"{len(report['extra'])} extra"
        )

        return report

    # -------------------------------------------------------------------------
    # Update Dependencies
    # -------------------------------------------------------------------------

    def update_dependencies(
        self,
        packages: Optional[list] = None,
        input_file: Optional[Path] = None,
        output_file: Optional[Path] = None,
    ) -> LockFile:
        """
        Update dependencies in the lock file.

        If packages is None, updates all dependencies.
        If packages is a list of package names, updates only those packages.
        """
        input_file = input_file or self.requirements_in
        output_file = output_file or self.requirements_lock

        if packages:
            logger.info(f"Updating specific packages: {', '.join(packages)}")
            return self._update_specific_packages(packages, input_file, output_file)
        else:
            logger.info("Updating all dependencies")
            return self.generate_lock_file(input_file, output_file)

    def _update_specific_packages(
        self, packages: list, input_file: Path, output_file: Path
    ) -> LockFile:
        """Update specific packages while keeping others pinned."""
        try:
            current_lock = self.read_lock_file()
        except FileNotFoundError:
            logger.warning("No existing lock file, generating fresh")
            return self.generate_lock_file(input_file, output_file)

        # Create a temporary constraints file with all packages EXCEPT the ones to update
        packages_to_update = {self._normalize_name(p) for p in packages}

        with tempfile.NamedTemporaryFile(
            mode="w", suffix=".txt", delete=False, prefix="constraints_"
        ) as tmp:
            for name, dep in current_lock.dependencies.items():
                if name not in packages_to_update:
                    tmp.write(f"{name}=={dep.version}\n")
            constraints_file = tmp.name

        try:
            # Try pip-compile with constraints
            cmd = [
                sys.executable, "-m", "piptools", "compile",
                "--output-file", "-",
                "--no-header",
                "--no-annotate",
                "--constraint", constraints_file,
                str(input_file),
            ]

            result = subprocess.run(
                cmd, capture_output=True, text=True, timeout=300
            )

            if result.returncode == 0:
                # Parse the output and regenerate with hashes
                return self.generate_lock_file(input_file, output_file)
            else:
                logger.warning(
                    f"Constrained update failed, doing full update: {result.stderr}"
                )
                return self.generate_lock_file(input_file, output_file)

        finally:
            os.unlink(constraints_file)

    # -------------------------------------------------------------------------
    # Sync Environment
    # -------------------------------------------------------------------------

    def sync_environment(self, dev: bool = False):
        """
        Synchronize the current environment to exactly match the lock file.

        This will:
        1. Install all packages from the lock file with hash verification
        2. Uninstall any packages not in the lock file
        """
        lock_file = self.requirements_dev_lock if dev else self.requirements_lock

        if not lock_file.exists():
            logger.error(f"Lock file not found: {lock_file}")
            logger.info("Run 'generate' first to create a lock file")
            return False

        logger.info(f"Syncing environment to {lock_file}")

        # Install from lock file with hash verification
        cmd = [
            sys.executable, "-m", "pip", "install",
            "--require-hashes",
            "--no-deps",  # Don't resolve deps, trust the lock file
            "-r", str(lock_file),
        ]

        result = subprocess.run(cmd, capture_output=True, text=True)

        if result.returncode != 0:
            logger.error(f"Installation failed:\n{result.stderr}")
            return False

        logger.info("Environment synced successfully")
        return True

    # -------------------------------------------------------------------------
    # Diff
    # -------------------------------------------------------------------------

    def diff_environment(self) -> dict:
        """Show differences between the lock file and current environment."""
        report = self.verify_environment()

        if "error" in report:
            return report

        print("\n" + "=" * 60)
        print("DEPENDENCY DIFF REPORT")
        print("=" * 60)

        if report["matched"]:
            print(f"\n✅ Matched ({len(report['matched'])} packages):")
            for pkg in report["matched"]:
                print(f"   {pkg['name']}=={pkg['version']}")

        if report["mismatched"]:
            print(f"\n⚠️  Mismatched ({len(report['mismatched'])} packages):")
            for pkg in report["mismatched"]:
                print(
                    f"   {pkg['name']}: "
                    f"expected {pkg['expected_version']}, "
                    f"installed {pkg['installed_version']}"
                )

        if report["missing"]:
            print(f"\n❌ Missing ({len(report['missing'])} packages):")
            for pkg in report["missing"]:
                print(f"   {pkg['name']}=={pkg['expected_version']}")

        if report["extra"]:
            print(f"\n➕ Extra ({len(report['extra'])} packages):")
            for pkg in report["extra"]:
                print(f"   {pkg['name']}=={pkg['installed_version']}")

        print("\n" + "=" * 60)
        return report

    # -------------------------------------------------------------------------
    # Audit
    # -------------------------------------------------------------------------

    def audit_dependencies(self) -> dict:
        """
        Audit dependencies for known security vulnerabilities.

        Uses pip-audit if available, otherwise provides basic checks.
        """
        logger.info("Auditing dependencies for vulnerabilities...")

        # Try pip-audit
        try:
            lock_file = self.requirements_lock
            if not lock_file.exists():
                logger.error("No lock file found. Run 'generate' first.")
                return {"error": "No lock file found"}

            cmd = [
                sys.executable, "-m", "pip_audit",
                "-r", str(lock_file),
                "--format", "json",
            ]

            result = subprocess.run(
                cmd, capture_output=True, text=True, timeout=120
            )

            if result.returncode == 0 or result.stdout:
                try:
                    audit_data = json.loads(result.stdout)
                    vulnerabilities = audit_data.get("dependencies", [])
                    vuln_count = sum(
                        len(d.get("vulns", []))
                        for d in vulnerabilities
                        if d.get("vulns")
                    )

                    if vuln_count == 0:
                        logger.info("✅ No known vulnerabilities found")
                    else:
                        logger.warning(
                            f"⚠️  Found {vuln_count} vulnerabilities"
                        )
                        for dep in vulnerabilities:
                            for vuln in dep.get("vulns", []):
                                logger.warning(
                                    f"  {dep['name']}=={dep['version']}: "
                                    f"{vuln.get('id', 'Unknown')} - "
                                    f"{vuln.get('description', 'No description')[:100]}"
                                )

                    return audit_data

                except json.JSONDecodeError:
                    logger.warning("Could not parse pip-audit output")

        except (subprocess.TimeoutExpired, FileNotFoundError):
            logger.info(
                "pip-audit not available. Install with: pip install pip-audit"
            )

        # Fallback: basic version age check
        return self._basic_audit()

    def _basic_audit(self) -> dict:
        """Basic audit: check if packages have newer versions available."""
        try:
            lock = self.read_lock_file()
        except FileNotFoundError:
            return {"error": "No lock file found"}

        outdated = []
        for name, dep in lock.dependencies.items():
            try:
                url = f"https://pypi.org/pypi/{name}/json"
                with urlopen(url, timeout=10) as response:
                    data = json.loads(response.read().decode())
                    latest = data.get("info", {}).get("version", "")
                    if latest and latest != dep.version:
                        outdated.append({
                            "name": name,
                            "current": dep.version,
                            "latest": latest,
                        })
            except (URLError, json.JSONDecodeError):
                continue

        if outdated:
            logger.info(f"Found {len(outdated)} outdated packages:")
            for pkg in outdated:
                logger.info(
                    f"  {pkg['name']}: {pkg['current']} -> {pkg['latest']}"
                )
        else:
            logger.info("All packages are up to date")

        return {"outdated": outdated}

    # -------------------------------------------------------------------------
    # Poetry Support
    # -------------------------------------------------------------------------

    def setup_poetry_project(self):
        """
        Generate Poetry configuration for projects using Poetry.

        Creates or updates pyproject.toml with proper dependency management settings.
        """
        pyproject = self.project_root / "pyproject.toml"

        if pyproject.exists():
            logger.info(f"pyproject.toml already exists at {pyproject}")
            logger.info("Use 'poetry lock' to generate/update poetry.lock")
            logger.info("Use 'poetry install --no-root' to install from lock file")
            return

        template = '''[tool.poetry]
name = "my-project"
version = "0.1.0"
description = "Project description"
authors = ["Team <team@example.com>"]

[tool.poetry.dependencies]
python = "^3.9"
# Add your production dependencies here:
# flask = "^2.0"
# sqlalchemy = "^2.0"

[tool.poetry.group.dev.dependencies]
# Add your development dependencies here:
# pytest = "^7.0"
# black = "^23.0"
# mypy = "^1.0"

[build-system]
requires = ["poetry-core"]
build-backend = "poetry.core.masonry.api"

# Recommended Poetry settings for reproducible builds:
# Run: poetry config virtualenvs.in-project true
# This creates .venv in the project directory
'''

        with open(pyproject, "w") as f:
            f.write(template)

        logger.info(f"Created {pyproject}")
        logger.info("Next steps:")
        logger.info("  1. Edit pyproject.toml to add your dependencies")
        logger.info("  2. Run 'poetry lock' to generate poetry.lock")
        logger.info("  3. Commit both pyproject.toml and poetry.lock to version control")
        logger.info("  4. Run 'poetry install' to install dependencies")

    def verify_poetry_lock(self) -> bool:
        """Verify that poetry.lock is consistent with pyproject.toml."""
        poetry_lock = self.project_root / "poetry.lock"
        pyproject = self.project_root / "pyproject.toml"

        if not poetry_lock.exists() or not pyproject.exists():
            logger.error("poetry.lock or pyproject.toml not found")
            return False

        try:
            result = subprocess.run(
                ["poetry", "check", "--lock"],
                capture_output=True,
                text=True,
                cwd=str(self.project_root),
            )

            if result.returncode == 0:
                logger.info("✅ poetry.lock is consistent with pyproject.toml")
                return True
            else:
                logger.error(
                    f"❌ poetry.lock is inconsistent: {result.stderr}"
                )
                logger.info("Run 'poetry lock' to update")
                return False

        except FileNotFoundError:
            logger.error("Poetry is not installed")
            return False

    # -------------------------------------------------------------------------
    # Utility Methods
    # -------------------------------------------------------------------------

    @staticmethod
    def _normalize_name(name: str) -> str:
        """Normalize package name per PEP 503."""
        return re.sub(r"[-_.]+", "-", name).lower().strip()

    def create_sample_requirements_in(self):
        """Create a sample requirements.in file with documentation."""
        if self.requirements_in.exists():
            logger.warning(f"{self.requirements_in} already exists, skipping")
            return

        sample = """#
# Direct project dependencies
# ===========================
#
# This file lists your project's direct dependencies with flexible version
# constraints. The lock file (requirements.lock) will be generated from this
# file with exact pinned versions and integrity hashes.
#
# Version constraint syntax:
#   package==1.0.0    # Exact version (not recommended here, use in lock file)
#   package>=1.0,<2.0 # Compatible range
#   package~=1.0      # Compatible release (~=1.0 means >=1.0,<2.0)
#   package>=1.0      # Minimum version
#
# To regenerate the lock file after editing this file:
#   python dependency_manager.py generate
#

# Web framework
# flask>=2.0,<4.0

# Database
# sqlalchemy>=2.0,<3.0

# Add your dependencies below:
"""

        with open(self.requirements_in, "w") as f:
            f.write(sample)

        logger.info(f"Created sample {self.requirements_in}")

        # Also create dev requirements
        if not self.requirements_dev_in.exists():
            dev_sample = """#
# Development dependencies
# ========================
#
# These are only needed for development, testing, and CI.
# They should NOT be installed in production.
#
# -r requirements.in  # Include production dependencies

# Testing
# pytest>=7.0
# pytest-cov>=4.0

# Code quality
# black>=23.0
# ruff>=0.1.0
# mypy>=1.0

# Security
# pip-audit>=2.0
"""
            with open(self.requirements_dev_in, "w") as f:
                f.write(dev_sample)

            logger.info(f"Created sample {self.requirements_dev_in}")


# =============================================================================
# CI/CD Integration Helpers
# =============================================================================

class CIIntegration:
    """Helpers for integrating dependency management into CI/CD pipelines."""

    @staticmethod
    def generate_github_actions_workflow(output_dir: str = ".github/workflows"):
        """Generate a GitHub Actions workflow for dependency management."""
        os.makedirs(output_dir, exist_ok=True)

        workflow = """# Auto-generated by dependency_manager.py
name: Dependency Management

on:
  pull_request:
    paths:
      - 'requirements.in'
      - 'requirements-dev.in'
      - 'requirements.lock'
      - 'requirements-dev.lock'
      - 'dependency-lock.json'
  schedule:
    # Weekly dependency audit
    - cron: '0 9 * * 1'

jobs:
  verify-lock-file:
    name: Verify Lock File
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Set up Python
        uses: actions/setup-python@v5
        with:
          python-version: '3.11'

      - name: Install from lock file
        run: |
          pip install --require-hashes --no-deps -r requirements.lock

      - name: Verify environment
        run: |
          python dependency_manager.py verify

  audit:
    name: Security Audit
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Set up Python
        uses: actions/setup-python@v5
        with:
          python-version: '3.11'

      - name: Install pip-audit
        run: pip install pip-audit

      - name: Audit dependencies
        run: |
          pip-audit -r requirements.lock

  check-lock-freshness:
    name: Check Lock File Freshness
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Set up Python
        uses: actions/setup-python@v5
        with:
          python-version: '3.11'

      - name: Install pip-tools
        run: pip install pip-tools

      - name: Verify lock file is up to date
        run: |
          python dependency_manager.py generate
          git diff --exit-code requirements.lock || \\
            (echo "Lock file is out of date. Run 'python dependency_manager.py generate'" && exit 1)
"""

        filepath = os.path.join(output_dir, "dependency-management.yml")
        with open(filepath, "w") as f:
            f.write(workflow)

        logger.info(f"Generated GitHub Actions workflow: {filepath}")

    @staticmethod
    def generate_dockerfile_snippet() -> str:
        """Generate Dockerfile snippet for secure dependency installation."""
        return """# =============================================================================
# Dockerfile snippet for secure dependency installation
# =============================================================================

# Stage 1: Install dependencies
FROM python:3.11-slim as dependencies

WORKDIR /app

# Copy only dependency files first (for better layer caching)
COPY requirements.lock .

# Install dependencies with hash verification
# --require-hashes: Verify package integrity
# --no-deps: Don't resolve dependencies (trust the lock file)
# --no-cache-dir: Don't cache downloaded packages (smaller image)
RUN pip install --no-cache-dir --require-hashes --no-deps -r requirements.lock

# Stage 2: Application
FROM python:3.11-slim

WORKDIR /app

# Copy installed packages from dependencies stage
COPY --from=dependencies /usr/local/lib/python3.11/site-packages /usr/local/lib/python3.11/site-packages
COPY --from=dependencies /usr/local/bin /usr/local/bin

# Copy application code
COPY . .

# Run as non-root user
RUN useradd --create-home appuser
USER appuser

CMD ["python", "-m", "your_app"]
"""

    @staticmethod
    def generate_makefile_targets() -> str:
        """Generate Makefile targets for dependency management."""
        return """# =============================================================================
# Dependency Management Makefile Targets
# =============================================================================

.PHONY: deps-install deps-lock deps-update deps-verify deps-audit deps-sync

# Install dependencies from lock file with hash verification
deps-install:
\tpip install --require-hashes --no-deps -r requirements.lock

# Install dev dependencies
deps-install-dev:
\tpip install --require-hashes --no-deps -r requirements-dev.lock

# Generate/regenerate lock files
deps-lock:
\tpython dependency_manager.py generate

# Update all dependencies
deps-update:
\tpython dependency_manager.py update

# Update a specific package (usage: make deps-update-pkg PKG=flask)
deps-update-pkg:
\tpython dependency_manager.py update $(PKG)

# Verify environment matches lock file
deps-verify:
\tpython dependency_manager.py verify

# Audit for security vulnerabilities
deps-audit:
\tpython dependency_manager.py audit

# Sync environment to exactly match lock file
deps-sync:
\tpython dependency_manager.py sync

# Show diff between lock file and environment
deps-diff:
\tpython dependency_manager.py diff
"""


# =============================================================================
# CLI Interface
# =============================================================================

def print_usage():
    """Print usage information."""
    print("""
Dependency Lock File Manager
=============================

Usage: python dependency_manager.py <command> [options]

Commands:
  init          Initialize dependency management files (requirements.in, etc.)
  generate      Generate lock file from requirements.in
  verify        Verify installed packages match the lock file
  update [pkg]  Update all dependencies or a specific package
  sync          Sync environment to exactly match the lock file
  diff          Show differences between lock file and environment
  audit         Audit dependencies for known vulnerabilities
  ci-setup      Generate CI/CD integration files
  poetry-init   Initialize Poetry-based dependency management
  poetry-verify Verify Poetry lock file consistency
  help          Show this help message

Workflow:
  1. Edit requirements.in with your direct dependencies
  2. Run 'python dependency_manager.py generate' to create lock file
  3. Commit requirements.in, requirements.lock, and dependency-lock.json
  4. In CI/production: pip install --require-hashes -r requirements.lock
  5. Periodically run 'python dependency_manager.py audit' for security

Files:
  requirements.in        Human-maintained direct dependencies (flexible versions)
  requirements-dev.in    Human-maintained dev dependencies
  requirements.lock      Auto-generated lock file (pinned versions + hashes)
  requirements-dev.lock  Auto-generated dev lock file
  dependency-lock.json   Auto-generated JSON lock file (for tooling)
""")


def main():
    """Main entry point for the CLI."""
    if len(sys.argv) < 2 or sys.argv[1] in ("help", "--help", "-h"):
        print_usage()
        return

    command = sys.argv[1].lower()
    manager = LockFileManager()

    if command == "init":
        manager.create_sample_requirements_in()
        print("\n✅ Initialized dependency management files.")
        print("Next steps:")
        print("  1. Edit requirements.in with your dependencies")
        print("  2. Run: python dependency_manager.py generate")

    elif command == "generate":
        try:
            lock = manager.generate_lock_file()
            print(f"\n✅ Generated lock file with {len(lock.dependencies)} packages")
            print("Install with: pip install --require-hashes -r requirements.lock")
        except FileNotFoundError as e:
            print(f"\n❌ {e}")
            print("Run 'python dependency_manager.py init' first")
            sys.exit(1)

    elif command == "verify":
        report = manager.verify_environment()
        if "error" in report:
            print(f"\n❌ {report['error']}")
            sys.exit(1)

        issues = len(report["mismatched"]) + len(report["missing"])
        if issues == 0:
            print("\n✅ Environment matches lock file")
        else:
            print(f"\n⚠️  Found {issues} issues")
            manager.diff_environment()
            sys.exit(1)

    elif command == "update":
        packages = sys.argv[2:] if len(sys.argv) > 2 else None
        try:
            lock = manager.update_dependencies(packages=packages)
            print(f"\n✅ Updated lock file with {len(lock.dependencies)} packages")
        except FileNotFoundError as e:
            print(f"\n❌ {e}")
            sys.exit(1)

    elif command == "sync":
        dev = "--dev" in sys.argv
        success = manager.sync_environment(dev=dev)
        if success:
            print("\n✅ Environment synced to lock file")
        else:
            print("\n❌ Sync failed")
            sys.exit(1)

    elif command == "diff":
        manager.diff_environment()

    elif command == "audit":
        result = manager.audit_dependencies()
        if "error" in result:
            print(f"\n❌ {result['error']}")
            sys.exit(1)

    elif command == "ci-setup":
        ci = CIIntegration()
        ci.generate_github_actions_workflow()
        print("\nGenerated CI/CD files:")
        print("  - .github/workflows/dependency-management.yml")
        print("\nDockerfile snippet:")
        print(ci.generate_dockerfile_snippet())
        print("\nMakefile targets:")
        print(ci.generate_makefile_targets())

    elif command == "poetry-init":
        manager.setup_poetry_project()

    elif command == "poetry-verify":
        success = manager.verify_poetry_lock()
        if not success:
            sys.exit(1)

    else:
        print(f"Unknown command: {command}")
        print_usage()
        sys.exit(1)


if __name__ == "__main__":
    main()